const update = $input.first().json;
const msg = update.message || {};

const text = msg.text || '';
const hasVoice = !!msg.voice;

if (!text && !hasVoice) {
  return [];
}

return [{
  json: {
    telegram_chat_id: String(msg.chat?.id || ''),
    telegram_message_id: String(msg.message_id || ''),
    text: text,
    raw_text: text,
    source_type: hasVoice ? 'voice' : 'text',
    has_voice: hasVoice,
    voice_file_id: msg.voice?.file_id || null
  }
}];

const whisperResponse = $json;
const original = $('Is Voice?').first().json;

return [{
  json: {
    telegram_chat_id: original.telegram_chat_id,
    telegram_message_id: original.telegram_message_id,
    text: original.text,
    raw_text: whisperResponse.text || '',
    source_type: 'voice',
    has_voice: true,
    voice_file_id: original.voice_file_id,
    transcript: whisperResponse.text || ''
  }
}];

const data = $json;
const transcript = data.transcript || data.text || '';

if (!transcript) {
  return [];
}

return [{
  json: {
    message: transcript,
    telegram_chat_id: data.telegram_chat_id,
    telegram_message_id: data.telegram_message_id,
    source_type: data.source_type || 'text',
    voice_file_id: data.voice_file_id || null,
    raw_text: data.raw_text || transcript
  }
}];

const agentOutput = $json;
const original = $('Prepare Agent Input').first().json;

// AI Agent node returns { output: "text" } or just text
const text = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

return [{
  json: {
    telegram_chat_id: original.telegram_chat_id,
    text: text
  }
}];
